 const statements=[env.db.prepare(`DELETE FROM conversation_facet_heads WHERE tenant_id=?1 AND workspace_id=?2 AND conversation_id=?3 AND dimension_key!=?4`).bind(row.tenant_id,row.workspace_id,conversationId,PRIMARY_CATEGORY_DIMENSION)];
 for(const definition of nonCategory){const version=(versions.get(`${definition.dimension}\u0000${definition.value}`)||0)+1,id=`facet:${await digest({conversationId,dimension:definition.dimension,value:definition.value,version,inputDigest})}`;nonCategoryIds.push(id);statements.push(env.db.prepare(`INSERT INTO conversation_facet_results(id,tenant_id,workspace_id,conversation_id,dimension_key,value_key,result_version,classifier_key,classifier_version,input_digest,confidence,status,explanation_code,evidence_ids_json,evidence_set_hash,observed_at) VALUES(?1,?2,?3,?4,?5,?6,?7,'nexora_facet_classifier',?8,?9,?10,'supported',?11,?12,?13,CURRENT_TIMESTAMP)`).bind(id,row.tenant_id,row.workspace_id,conversationId,definition.dimension,definition.value,version,CLASSIFIER_VERSION,inputDigest,definition.confidence,definition.explanation,JSON.stringify([evidenceId]),evidenceSetHash),env.db.prepare(`INSERT INTO conversation_facet_heads(tenant_id,workspace_id,conversation_id,dimension_key,value_key,current_result_id,current_result_version) VALUES(?1,?2,?3,?4,?5,?6,?7)`).bind(row.tenant_id,row.workspace_id,conversationId,definition.dimension,definition.value,id,version));}
 statements.push(env.db.prepare(`UPDATE conversation_aggregates SET facet_generation=facet_generation+1,updated_at=CURRENT_TIMESTAMP WHERE id=?1 AND tenant_id=?2 AND workspace_id=?3`).bind(conversationId,row.tenant_id,row.workspace_id));await env.db.batch(statements);
 const source=await env.db.prepare(`SELECT source_version,account_id FROM conversation_messages WHERE tenant_id=?1 AND workspace_id=?2 AND conversation_id=?3 AND source_message_id=?4 AND lifecycle_state!='quarantined' ORDER BY observed_at DESC LIMIT 1`).bind(row.tenant_id,row.workspace_id,conversationId,row.email_id).first(),checkpoint=await env.db.prepare(`SELECT * FROM conversation_materialization_checkpoints WHERE tenant_id=?1 AND workspace_id=?2 AND state='running' AND lease_owner IS NOT NULL AND datetime(lease_until)>CURRENT_TIMESTAMP ORDER BY updated_at DESC LIMIT 1`).bind(row.tenant_id,row.workspace_id).first(),evidence=await env.db.prepare(`SELECT integrity_hash FROM conversation_evidence WHERE id=?1 AND tenant_id=?2 AND workspace_id=?3 AND verification_state='verified'`).bind(evidenceId,row.tenant_id,row.workspace_id).first();
